def ldef_rule(model, ss, sp, spp, bb):
    x_list = list(model.x)
    d_list = list(model.d)
    ordx = {lab: i + 1 for i, lab in enumerate(x_list)}
    cardx = len(x_list)
    df = {}
    for a in x_list:
        for c in x_list:
            df[(a, c)] = ordx[c] - ordx[a]
        df[(a, 'incr')] = 0
        df[(a, 'decr')] = 1 + cardx - 2 * ordx[a]
    ld = set()
    for y in x_list:
        for z in x_list:
            ld.add(('incr', y, z)); ld.add((y, 'incr', z)); ld.add((y, z, 'incr'))
    for dd in d_list:
        for z in x_list:
            ld.add(('incr', dd, z)); ld.add((z, 'incr', dd)); ld.add((dd, z, 'incr'))
        for dp in d_list:
            ld.add(('incr', dd, dp))
    if (ss, sp, spp) not in ld:
        return Constraint.Skip
    def cell(lab, direction):
        return x_list[ordx[lab] + df[(lab, direction)] - 1]
    lhs = model.ls[bb] * sum(model.core[cell(lab, ss), cell(lab, sp), cell(lab, spp)] for lab in x_list)
    return lhs <= model.line[ss, sp, spp] + model.lr[bb]
model.ldef = Constraint(model.s, model.s, model.s, model.b, rule=ldef_rule)

